### Server Startup

```typescript
// In sudocode local-server
async function startServer(config: ServerConfig) {
  // ... existing setup ...

  if (config.mesh?.enabled) {
    const meshService = new SudocodeMeshService({
      projectId: project.id,
      projectPath: project.path,
      meshConfig: config.mesh
    })

    await meshService.connect()

    // Wire up entity updates
    entityService.on('change', (entity) => {
      meshService.syncEntity(entity)
    })

    meshService.on('entity:updated', (entity, source) => {
      if (source === 'remote') {
        entityService.applyRemoteUpdate(entity)
      }
    })
  }
}
